using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>
/// Simulated web-search tool — returns canned results for demonstration.
/// Replace the body with a real search API call (e.g. Bing Search) in production.
/// </summary>
[Description("Searches the web for information on a given query and returns a list of results with titles, URLs, and snippets.")]
static string SearchWeb([Description("The search query")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  🔍  Searching the web for: \"{query}\"");
    Console.ResetColor();

    // Simulated search results keyed on topic keywords
    var results = new[]
    {
        new { Title = $"Overview of {query} - Wikipedia",           Url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}", Snippet = $"A comprehensive overview covering the history, key concepts, and current state of {query}." },
        new { Title = $"Latest research on {query} - Nature",       Url = $"https://nature.com/articles/{Uri.EscapeDataString(query)}",   Snippet = $"Recent peer-reviewed findings highlight breakthroughs and open questions in {query}." },
        new { Title = $"{query}: Practical applications - MIT Tech", Url = $"https://technologyreview.com/{Uri.EscapeDataString(query)}", Snippet = $"How {query} is being applied in industry, healthcare, and everyday life." },
        new { Title = $"Challenges facing {query} - IEEE Spectrum",  Url = $"https://spectrum.ieee.org/{Uri.EscapeDataString(query)}",    Snippet = $"An analysis of the technical and societal challenges that remain for {query}." },
    };

    return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
}

/// <summary>
/// A simple in-memory notepad the agent can write to while researching.
/// </summary>
var notebook = new List<string>();

[Description("Saves a research note. Use this to record important findings, quotes, or key points discovered during research.")]
string SaveNote([Description("The note text to save")] string note)
{
    notebook.Add(note);

    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  📝  Note saved ({notebook.Count} total)");
    Console.ResetColor();

    return $"Note saved. You now have {notebook.Count} note(s).";
}

[Description("Retrieves all previously saved research notes.")]
string GetNotes()
{
    if (notebook.Count == 0)
        return "No notes have been saved yet.";

    var sb = new StringBuilder();
    for (int i = 0; i < notebook.Count; i++)
        sb.AppendLine($"[{i + 1}] {notebook[i]}");

    return sb.ToString();
}

// ---------------------------------------------------------------------------
// Build the agent
// ---------------------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? string.Empty;
var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("ERROR: Set the OPENAI_API_KEY environment variable before running.");
    Console.ResetColor();
    return;
}

IChatClient chatClient = new OpenAI.Chat.ChatClient(model, apiKey).AsIChatClient();

AIFunction searchTool   = AIFunctionFactory.Create(SearchWeb);
AIFunction saveNoteTool = AIFunctionFactory.Create(SaveNote);
AIFunction getNotesTool = AIFunctionFactory.Create(GetNotes);

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic you:
        1. Search the web for relevant information using the SearchWeb tool.
        2. Save important findings as notes using the SaveNote tool.
        3. Optionally search again to fill gaps.
        4. Retrieve your notes with GetNotes to review what you have gathered.
        5. Produce a well-structured summary with sections: Overview, Key Findings,
           Applications, Challenges, and References (include URLs).
        Be thorough — use the tools multiple times if needed.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: [searchTool, saveNoteTool, getNotesTool]);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬 Research Agent Started         ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching \"{topic}\" — this may take a moment...");
Console.WriteLine(new string('─', 50));

AgentResponse response = await agent.RunAsync($"Research the following topic and provide a detailed summary: {topic}");

Console.WriteLine(new string('─', 50));
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("\n📋  RESEARCH SUMMARY\n");
Console.ResetColor();
Console.WriteLine(response.Text);

