         new { Title = $"{query}: Practical applications - MIT Tech", Url = $"https://technologyreview.com/{Uri.EscapeDataString(query)}", Snippet = $"How {query} is being applied in industry, healthcare, and everyday life." },
         new { Title = $"Challenges facing {query} - IEEE Spectrum",  Url = $"https://spectrum.ieee.org/{Uri.EscapeDataString(query)}",    Snippet = $"An analysis of the technical and societal challenges that remain for {query}." },
     };

     return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
 }

 /// <summary>
 /// A simple in-memory notepad the agent can write to while researching.
 /// </summary>
 var notebook = new List<string>();

 [Description("Saves a research note. Use this to record important findings, quotes, or key points discovered during research.")]
 string SaveNote([Description("The note text to save")] string note)
 {
     notebook.Add(note);

     Console.ForegroundColor = ConsoleColor.DarkCyan;
     Console.WriteLine($"  📝  Note saved ({notebook.Count} total)");
     Console.ResetColor();

     return $"Note saved. You now have {notebook.Count} note(s).";
 }

 [Description("Retrieves all previously saved research notes.")]
 string GetNotes()
 {
     if (notebook.Count == 0)
         return "No notes have been saved yet.";

     var sb = new StringBuilder();
     for (int i = 0; i < notebook.Count; i++)
         sb.AppendLine($"[{i + 1}] {notebook[i]}");

     return sb.ToString();
 }

