 // Build the agent
 // ---------------------------------------------------------------------------

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? string.Empty;
 var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

 if (string.IsNullOrWhiteSpace(apiKey))
 {
     Console.ForegroundColor = ConsoleColor.Red;
     Console.WriteLine("ERROR: Set the OPENAI_API_KEY environment variable before running.");
     Console.ResetColor();
     return;
 }

 IChatClient chatClient = new OpenAI.Chat.ChatClient(model, apiKey).AsIChatClient();

 AIFunction searchTool   = AIFunctionFactory.Create(SearchWeb);
 AIFunction saveNoteTool = AIFunctionFactory.Create(SaveNote);
 AIFunction getNotesTool = AIFunctionFactory.Create(GetNotes);

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research assistant. When given a topic you:
         1. Search the web for relevant information using the SearchWeb tool.
         2. Save important findings as notes using the SaveNote tool.
         3. Optionally search again to fill gaps.
         4. Retrieve your notes with GetNotes to review what you have gathered.
         5. Produce a well-structured summary with sections: Overview, Key Findings,
            Applications, Challenges, and References (include URLs).
         Be thorough — use the tools multiple times if needed.
         """,
     name: "ResearchAgent",
     description: "An AI agent that researches topics by searching the web and taking notes.",
     tools: [searchTool, saveNoteTool, getNotesTool]);

